import React, { useState } from 'react';
import axios from 'axios';

function Registration() {
  // 1. Initial State matching your updated Backend Schema
  const [formData, setFormData] = useState({
    fullName: '',
    email: '',
    serviceType: 'Web Development',
    projectDetails: '',
    paymentMethod: 'Cash',
    totalBudget: 0,   // Added to prevent undefined errors in Admin
    advancePaid: 0    // Added to prevent undefined errors in Admin
  });

  const [message, setMessage] = useState('');
  const [loading, setLoading] = useState(false);

  // 2. Handle Input Changes
  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  // 3. Handle Form Submission
  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage('');

    try {
      // Simulation for Online Payment
      if (formData.paymentMethod === 'Online') {
        alert("Redirecting to Secure Online Payment Gateway...");
        // Note: For real integration, add Razorpay/Stripe logic here
      }

      // API Call to your Node.js Backend
      const response = await axios.post('http://localhost:5000/api/hire', formData);
      
      if (response.status === 201) {
        setMessage("✅ Success! Your request has been sent. You can track it on the Live Tracker.");
        
        // Reset form fields
        setFormData({ 
          fullName: '', 
          email: '', 
          serviceType: 'Web Development', 
          projectDetails: '', 
          paymentMethod: 'Cash',
          totalBudget: 0,
          advancePaid: 0
        });
      }
    } catch (error) {
      console.error("Error saving data:", error);
      setMessage("❌ Error! Could not connect to the server. Please ensure Backend is running.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container py-5">
      <div className="row justify-content-center">
        <div className="col-md-6 col-lg-5">
          <div className="card shadow-lg border-0 rounded-4 p-4">
            <h2 className="text-center fw-bold mb-4 text-primary">Hire Me</h2>
            
            {/* Status Message Display */}
            {message && (
              <div className={`alert ${message.includes('Success') ? 'alert-success' : 'alert-danger'} text-center py-2 shadow-sm`}>
                {message}
              </div>
            )}

            <form onSubmit={handleSubmit}>
              {/* Full Name */}
              <div className="mb-3">
                <label className="form-label fw-bold small">Full Name</label>
                <input 
                  type="text" 
                  name="fullName" 
                  className="form-control py-2" 
                  placeholder="Enter your name"
                  value={formData.fullName} 
                  onChange={handleChange} 
                  required 
                />
              </div>

              {/* Email Address */}
              <div className="mb-3">
                <label className="form-label fw-bold small">Email Address</label>
                <input 
                  type="email" 
                  name="email" 
                  className="form-control py-2" 
                  placeholder="name@example.com"
                  value={formData.email} 
                  onChange={handleChange} 
                  required 
                />
              </div>

              {/* Service Selection */}
              <div className="mb-3">
                <label className="form-label fw-bold small">Select Service</label>
                <select name="serviceType" className="form-select py-2" value={formData.serviceType} onChange={handleChange}>
                  <option value="Web Development">Web Development</option>
                  <option value="UI/UX Design">UI/UX Design</option>
                  <option value="Assignment Support">Assignment Support</option>
                  <option value="Report Writing">Report Writing</option>
                </select>
              </div>

              {/* Payment Method */}
              <div className="mb-3">
                <label className="form-label fw-bold small text-danger">Payment Method</label>
                <select name="paymentMethod" className="form-select border-danger py-2" value={formData.paymentMethod} onChange={handleChange}>
                  <option value="Cash">Cash / Direct Pay (After Work)</option>
                  <option value="Online">Online Payment (UPI / Card)</option>
                </select>
                <div className="form-text mt-1 text-muted small">
                  Note: Online payment is simulated for demo purposes.
                </div>
              </div>

              {/* Project Details */}
              <div className="mb-4">
                <label className="form-label fw-bold small">Project Details</label>
                <textarea 
                  name="projectDetails" 
                  className="form-control" 
                  rows="3" 
                  placeholder="Describe your project briefly..."
                  value={formData.projectDetails} 
                  onChange={handleChange} 
                  required 
                ></textarea>
              </div>

              <button type="submit" className="btn btn-primary w-100 fw-bold py-2 shadow" disabled={loading}>
                {loading ? "Sending..." : "Send Request & Continue"}
              </button>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Registration;
